/**
 * cookie-signature
 * 
 * Sign and unsign cookies with HMAC signatures for Express.js
 * This module provides cryptographic integrity for cookies used in Express applications
 */

/**
 * Module dependencies.
 */
var crypto = require('crypto');

/**
 * Sign the given `val` with `secret`.
 *
 * @param {String} val - Value to sign
 * @param {String} secret - Secret key for signing
 * @return {String} Signed value as 's:' + signature
 * @api public
 */
exports.sign = function(val, secret){
  if ('string' != typeof val) throw new TypeError('Cookie value must be provided as a string');
  if ('string' != typeof secret) throw new TypeError('Secret key must be provided as a string');
  
  // Create HMAC using SHA256 algorithm
  var hmac = crypto.createHmac('sha256', secret);
  
  // Update HMAC with the value
  hmac.update(val);
  
  // Return signed value with 's:' prefix
  return 's:' + val + '.' + hmac.digest('base64')
    .replace(/\+/g, '-')
    .replace(/\//g, '_')
    .replace(/=/g, '');
};

/**
 * Unsign and verify the given `val` with `secret`.
 *
 * @param {String} val - Signed value to verify
 * @param {String} secret - Secret key for verification
 * @return {String|Boolean} Original value if valid, false otherwise
 * @api public
 */
exports.unsign = function(val, secret){
  if ('string' != typeof val) throw new TypeError('Signed cookie value must be provided as a string');
  if ('string' != typeof secret) throw new TypeError('Secret key must be provided as a string');
  
  // Validate format
  var prefix = 's:';
  if (val.slice(0, prefix.length) !== prefix) {
    return false;
  }
  
  // Extract value and signature
  var str = val.slice(prefix.length);
  var dot = str.lastIndexOf('.');
  if (dot === -1) {
    return false;
  }
  
  var value = str.slice(0, dot);
  var signature = str.slice(dot + 1);
  
  // Create HMAC using SHA256 algorithm
  var hmac = crypto.createHmac('sha256', secret);
  
  // Update HMAC with the value
  hmac.update(value);
  
  // Get expected signature
  var expectedSignature = hmac.digest('base64')
    .replace(/\+/g, '-')
    .replace(/\//g, '_')
    .replace(/=/g, '');
  
  // Verify signature using timing-safe comparison
  return timingSafeEqual(signature, expectedSignature) ? value : false;
};

/**
 * Perform a timing-safe comparison between two strings
 * This helps prevent timing attacks when verifying signatures
 *
 * @param {String} a - First string to compare
 * @param {String} b - Second string to compare
 * @return {Boolean} True if equal, false otherwise
 * @api private
 */
function timingSafeEqual(a, b) {
  if (a.length !== b.length) {
    return false;
  }
  
  // If native crypto.timingSafeEqual is available (Node.js >= 6.6.0), use it
  if (crypto.timingSafeEqual && Buffer.isBuffer(a) && Buffer.isBuffer(b)) {
    return crypto.timingSafeEqual(a, b);
  }
  
  // Otherwise, implement our own timing-safe comparison
  var result = 0;
  for (var i = 0; i < a.length; i++) {
    result |= (a.charCodeAt(i) ^ b.charCodeAt(i));
  }
  return result === 0;
};